"use client";

import React, { useState, useEffect } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { useTranslation } from "react-i18next";

const SidebarItem = ({ item, pageName, setPageName, index = 0 }) => {
  const { t } = useTranslation();
  const [isHovered, setIsHovered] = useState(false);
  const [isMobile, setIsMobile] = useState(false);

  const handleClick = () => {
    const updatedPageName =
      pageName !== item.label.toLowerCase() ? item.label.toLowerCase() : "";
    setPageName(updatedPageName);
  };

  const pathname = usePathname();

  const isActive = (item) => {
    if (pathname.startsWith(item.route)) return true;

    if (item.children) {
      return item.children.some((child) => isActive(child));
    }

    return false;
  };

  const isItemActive = isActive(item);

  // Check if the screen width is mobile
  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
    };

    // Initial check
    handleResize();

    // Add event listener
    window.addEventListener("resize", handleResize);

    // Cleanup event listener
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  return (
    <li 
      className="animate-fade-in w-full list-none"
      style={{ animationDelay: `${index * 0.05}s`, animationFillMode: 'both' }}
    >
      <Link
        href={item.route}
        onClick={handleClick}
        onMouseEnter={() => !isMobile && setIsHovered(true)}
        onMouseLeave={() => !isMobile && setIsHovered(false)}
        className={`
          group relative flex items-center rounded-xl py-3 px-4 font-medium text-sm
          transition-all duration-300 ease-in-out w-full min-w-0 overflow-hidden
          ${isItemActive 
            ? "bg-gradient-to-r from-purple-600/40 via-purple-500/30 to-green-500/40 shadow-lg shadow-purple-500/30 backdrop-blur-sm border border-purple-400/40" 
            : "bg-transparent hover:bg-gradient-to-r hover:from-purple-600/20 hover:via-purple-500/10 hover:to-green-500/20 border border-transparent hover:border-purple-400/20"
          }
          ${!isMobile ? "hover:shadow-lg hover:shadow-purple-500/20 hover:scale-[1.02]" : ""}
          ${isItemActive ? "scale-[1.02]" : ""}
        `}
      >
        {/* Active indicator bar with gradient */}
        {isItemActive && (
          <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-gradient-to-b from-green-400 via-green-300 to-purple-400 rounded-r-full shadow-lg shadow-green-400/50" />
        )}
        
        {/* Animated background gradient on hover/active */}
        <div 
          className={`
            absolute inset-0 rounded-xl bg-gradient-to-r from-purple-500/0 via-green-400/0 to-purple-500/0
            transition-all duration-500
            ${isHovered || isItemActive ? "from-purple-500/10 via-green-400/10 to-purple-500/10" : ""}
          `}
        />
        
        {/* Shimmer effect */}
        {(isHovered || isItemActive) && (
          <div className="absolute inset-0 rounded-xl bg-gradient-to-r from-transparent via-white/10 to-transparent animate-shimmer" />
        )}
        
        {/* Label with gradient text */}
        <span className={`
          relative z-10 transition-all duration-300 flex-1 text-left leading-tight
          ${isItemActive 
            ? "font-semibold bg-gradient-to-r from-green-200 via-white to-purple-200 bg-clip-text text-transparent" 
            : "font-medium text-white/90 group-hover:text-white"
          }
        `}>
          {item.translationKey ? t(item.translationKey) : item.label}
        </span>
        
        {/* Active indicator dot */}
        {isItemActive && (
          <div className="absolute right-3 top-1/2 -translate-y-1/2 w-2 h-2 rounded-full bg-gradient-to-r from-green-400 to-purple-400 shadow-lg shadow-green-400/50 animate-pulse" />
        )}
      </Link>
    </li>
  );
};

export default SidebarItem;
